DROP TABLE IF EXISTS J09A_temp;
CREATE TABLE J09A_temp AS
SELECT *
FROM decision_talbe
WHERE TOUR LIKE 'J09A%';
ALTER TABLE J09A_temp ADD COLUMN ENTSCHEIDUNG TEXT;
UPDATE J09A_temp
SET ENTSCHEIDUNG = CASE
  WHEN HAUS IN (
     SELECT HAUS
     FROM J09A_temp
     GROUP BY HAUS
     HAVING COUNT(DISTINCT EQUNR) < 3
  ) THEN 'KSA'
  ELSE 'EVU'
END;
UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;
